/**
 * @fileoverview ClipBox view — DOM setup / teardown + reactive effects + rendering.
 * @module module/ClipBox/view
 */

import { CLS, STATE_CLS, SEL, SPELL, SVG, DARKROOM_Z_INDEX, PART } from './constants.js';
import { defaultMapId, defaultMapValue, defaultMapLabel } from './helpers.js';
import razyui from '../../index.js';
import { positionFloating } from '../shared/positionFloating.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { setContent } from '../shared/setContent.js';

// ═══════════════════════════════════════
//  DOM Construction
// ═══════════════════════════════════════

/**
 * Build the primary ClipBox DOM: container + inner text input + floating dropdown.
 *
 * @param {Function} spell — `razyui.spell` helper
 * @param {HTMLInputElement} inputEl — original native `<input>`
 * @param {object} config — merged configuration
 * @returns {{ container: HTMLElement, textInput: HTMLInputElement, floating: HTMLElement, overflowBadge: HTMLElement|null, compactAnchor: HTMLElement|null }}
 */
export function buildDOM(spell, inputEl, config) {
    const dom = spell(SPELL.CONTAINER, true);
    const container = dom[0];
    const $container = razyui(container);
    PART.ROOT.apply($container);

    const textInput = dom.find('.' + CLS.INPUT)[0];
    PART.INPUT.apply(textInput);
    textInput.type = 'text';
    textInput.placeholder = config.placeholder || inputEl.placeholder || '';
    textInput.autocomplete = 'off';

    // Inline mode (e.g. GridTable cell) or cell mode (e.g. cell-row)
    if (config.renderContext) {
        if (config.renderContext === 'cell') {
            $container.addClass(STATE_CLS.CELL);
        } else {
            $container.addClass(STATE_CLS.INLINE);
        }
    }

    // Single-line mode
    if (config.singleLine) {
        $container.addClass(STATE_CLS.SINGLE_LINE);
    }

    // Compact mode setup
    let overflowBadge = null;
    if (config.compact) {
        $container.addClass(STATE_CLS.COMPACT);

        const badge = razyui.el('span', { className: CLS.OVERFLOW });
        PART.OVERFLOW.apply(badge[0] || badge);
        badge.css('display', 'none');
        overflowBadge = badge;
        $container.append(badge[0]);

        // Click hint — small edit icon to signal interactivity
        const hint = razyui.el('span', {
            className: CLS.COMPACT_HINT,
            innerHTML: SVG.COMPACT_HINT
        });
        PART.COMPACT_HINT.apply(hint[0] || hint);
        $container.append(hint[0]);
    }

    // Floating suggestion dropdown
    const floating = spell(SPELL.FLOATING, true)[0];
    PART.FLOATING.apply(floating);
    razyui(floating).css('display', 'none');

    // Insert container after input, hide native
    razyui(inputEl).css('display', 'none');
    inputEl.parentNode.insertBefore(container, inputEl.nextSibling);

    // Compact anchor — marks original position when container moves to darkroom
    let compactAnchor = null;
    if (config.compact) {
        const anchor = razyui.el('span');
        anchor.css('display', 'none');
        container.parentNode.insertBefore(anchor[0], container.nextSibling);
        compactAnchor = anchor;
    }

    return { container, textInput, floating, overflowBadge, compactAnchor };
}

// ═══════════════════════════════════════
//  Reactive Effects
// ═══════════════════════════════════════

/**
 * Wire reactive effects onto the stateSet.
 *
 * @param {object} stateSet — from `razyui.state()`
 * @param {object} ctx — { container, textInput, inputEl, config, renderChips, updateOverflow }
 */
export function wireEffects(stateSet, ctx) {
    const { container, textInput, inputEl, config, renderChips, updateOverflow } = ctx;

    // 1. Render chips whenever chip list changes
    stateSet.effect(function () {
        renderChips();
        if (config.compact) {
            requestAnimationFrame(() => updateOverflow());
        }
    });

    // 2. Sync disabled / readonly classes
    stateSet.effect(function () {
        razyui(container).toggleClass(STATE_CLS.DISABLED, !!this.disabled)
                         .toggleClass(STATE_CLS.READONLY, !!this.readonly);
        textInput.disabled = !!this.disabled;
        textInput.readOnly = !!this.readonly;
    });

    // 3. Sync hidden input value (separator-delimited id for form submit)
    stateSet.effect(function () {
        inputEl.value = this.chips.map(c => c.id).join(config.separator + ' ');
    });
}

// ═══════════════════════════════════════
//  Chip Rendering
// ═══════════════════════════════════════

/**
 * Render chip DOM elements into the container.
 *
 * @param {Function} spell — `razyui.spell` helper
 * @param {HTMLElement} container — clip-box root
 * @param {{ value: string, label: string }[]} chips — current chips
 * @param {HTMLInputElement} textInput — inner input element
 * @param {object} config — merged config
 */
export function renderChips(spell, container, chips, textInput, config) {
    // Remove existing chips
    razyui(container).find(SEL.CHIP).each(el => el.remove());

    for (const chip of chips) {
        const dom = spell(SPELL.CHIP, true);
        const el = dom[0];
        el.dataset.id = chip.id;

        const { label: chipLabel, remove } = dom.collect(
            { label: SEL.CHIP_LABEL, remove: SEL.REMOVE }, 0
        );
        PART.CHIP.apply(el);
        PART.CHIP_LABEL.apply(chipLabel[0]);
        PART.REMOVE.apply(remove[0]);
        chipLabel.text(chip.label);
        remove.attr('type', 'button').html(SVG.REMOVE);
        remove[0].tabIndex = -1;

        razyui(textInput).before(el);
    }

    // Update placeholder visibility
    textInput.placeholder = chips.length > 0 ? '' : (config.placeholder || '');

    // Hide input when max reached
    const maxReached = config.max > 0 && chips.length >= config.max;
    razyui(textInput).css('display', maxReached ? 'none' : '');
}

// ═══════════════════════════════════════
//  Error Display
// ═══════════════════════════════════════

/**
 * Show a tooltip error message on the container.
 *
 * @param {HTMLElement} container
 * @param {HTMLInputElement} textInput
 * @param {string} msg
 */
export function showError(container, textInput, msg) {
    clearError(container);

    const el = razyui.el('div', {
        className: CLS.ERROR,
        textContent: msg
    });
    PART.ERROR.apply(el[0] || el);
    razyui(container).append(el[0]).addClass(STATE_CLS.ERROR);

    // Clear when input loses focus
    const $textInput = razyui(textInput);
    const onBlur = () => {
        clearError(container);
        $textInput.off('blur', onBlur);
    };
    $textInput.on('blur', onBlur);
}

/**
 * Remove any visible error tooltip.
 *
 * @param {HTMLElement} container
 */
export function clearError(container) {
    const el = razyui(container).find(SEL.ERROR)[0];
    if (el) el.remove();
    razyui(container).removeClass(STATE_CLS.ERROR);
}

// ═══════════════════════════════════════
//  Suggestion Dropdown
// ═══════════════════════════════════════

/**
 * Render the suggestion dropdown with items.
 *
 * @param {object} ctx — { floating, container, config, stateRef, darkroom, addChip, textInput, attachOutsideClick }
 * @param {object[]} items — remote data items
 */
export function showSuggestions(ctx, items) {
    const { floating, container, config, stateRef, darkroom, addChip, textInput, attachOutsideClick } = ctx;

    const $floating = razyui(floating);
    $floating.html('');

    const mapId    = config.mapId    || defaultMapId;
    const mapValue = config.mapValue || defaultMapValue;
    const mapLabel = config.mapLabel || defaultMapLabel;

    for (const item of items) {
        const id    = mapId(item);
        const value = mapValue(item);
        const label = mapLabel(item);

        const row = razyui.el('div', {
            className: CLS.SUGGESTION,
            'data-id': id,
            'data-value': value,
            'data-label': label
        });
        PART.SUGGESTION.apply(row[0] || row);

        if (typeof config.onRenderSuggestion === 'function') {
            setContent(row, config.onRenderSuggestion(item));
        } else {
            row.text(label);
        }

        // Already added → dim (match by unique id)
        if (!config.allowDuplicate && stateRef.chips.some(c => c.id === id)) {
            row.addClass(STATE_CLS.ADDED);
        }

        $floating.append(row[0]);
    }

    // Position floating below container
    const gap = config.dropdownGap;

    if (darkroom) {
        // Inside darkroom — append after the container inside the darkroom body
        // so it flows naturally within the panel (no fixed positioning needed).
        const darkroomBody = container.parentNode;
        if (!floating.isConnected || floating.parentNode !== darkroomBody) {
            darkroomBody.appendChild(floating);
        }
        $floating.css({
                 display: '',
                 position: '',
                 left: '',
                 top: '',
                 'min-width': '',
                 width: '',
                 'z-index': '',
                 'margin-top': gap + 'px',
             });
    } else {
        // Normal mode — append to document.body with fixed positioning
        if (!floating.isConnected || floating.parentNode !== document.body) {
            razyui(document.body).append(floating);
        }
        $floating.css('margin-top', '');

        positionFloating(floating, container, {
            strategy: 'fixed',
            gap,
            flip:     false,
            width:    'min-match',
        });
        zIndexRegistry.acquire(floating);
    }

    // Suggestion click
    floating.onclick = (e) => {
        const row = razyui(e.target).closest('.' + CLS.SUGGESTION);
        if (!row.length || row.hasClass(STATE_CLS.ADDED)) return;
        const id  = row.data('id');
        const val = row.data('value');
        const lbl = row.data('label');
        if (addChip(id, val, lbl)) {
            textInput.value = '';
            // Mark as added
            row.addClass(STATE_CLS.ADDED);
        }
    };

    attachOutsideClick();
}

/**
 * Hide the suggestion dropdown.
 *
 * @param {HTMLElement} floating
 * @param {Function} detachOutsideClick
 */
export function hideFloating(floating, detachOutsideClick) {
    if (floating) {
        razyui(floating).css('display', 'none');
        zIndexRegistry.release(floating);
    }
    detachOutsideClick();
}

// ═══════════════════════════════════════
//  Compact Mode — Overflow
// ═══════════════════════════════════════

/**
 * Recalculate which chips are visible in compact mode and update the overflow badge.
 *
 * @param {HTMLElement} container
 * @param {HTMLElement} badge — overflow badge element
 * @param {boolean} hasDarkroom — whether darkroom is currently open
 */
export function updateOverflow(container, badge, hasDarkroom) {
    if (hasDarkroom) return;

    const chips = Array.from(container.querySelectorAll(SEL.CHIP));

    if (chips.length === 0) {
        badge.css('display', 'none');
        return;
    }

    // Reset: show all chips, hide badge for measurement
    chips.forEach(c => razyui(c).removeClass(STATE_CLS.OVERFLOW_HIDDEN));
    badge.css('display', 'none');

    const cs = getComputedStyle(container);
    const padL = parseFloat(cs.paddingLeft) || 0;
    const padR = parseFloat(cs.paddingRight) || 0;
    const gap = parseFloat(cs.gap) || 0;
    const available = container.clientWidth - padL - padR;

    // Measure badge width (temporarily show, invisible)
    badge.text('+' + chips.length)
         .css('display', '');
    badge.css('visibility', 'hidden');
    const badgeW = badge.prop('offsetWidth');
    badge.css({ visibility: '', display: 'none' });

    // Batch-read all chip widths to avoid interleaved layout reads/writes
    const chipWidths = chips.map(c => c.offsetWidth);

    let total = 0;
    let cutoff = chips.length;

    for (let i = 0; i < chips.length; i++) {
        const w = chipWidths[i];
        const acc = total + w + (i > 0 ? gap : 0);
        const remaining = chips.length - i - 1;
        const limit = remaining > 0 ? available - badgeW - gap : available;

        if (acc > limit) {
            cutoff = i;
            break;
        }
        total = acc;
    }

    if (cutoff < chips.length) {
        const hidden = chips.length - cutoff;
        for (let i = cutoff; i < chips.length; i++) {
            razyui(chips[i]).addClass(STATE_CLS.OVERFLOW_HIDDEN);
        }
        badge.text('+' + hidden)
             .css('display', '');
    }
}

// ═══════════════════════════════════════
//  Darkroom (Compact modal editor)
// ═══════════════════════════════════════

/**
 * Open the darkroom modal editor for chip editing.
 *
 * @param {object} ctx — { container, textInput, config, overflowBadge, compactAnchor }
 * @returns {{ overlay: HTMLElement, ghost: HTMLElement }}
 */
export function openDarkroom(ctx) {
    const { container, textInput, config, overflowBadge } = ctx;

    // ── Ghost element — preserves layout while container is in darkroom ──
    const cs = getComputedStyle(container);
    const ghost = razyui.el('div', { className: CLS.GHOST });
    ghost.css({ width: cs.width, height: cs.height });
    ghost.css('boxSizing', 'border-box');
    razyui(container).before(ghost[0]);

    // Build overlay
    const overlay = razyui.el('div', { className: CLS.DARKROOM_OVERLAY });
    PART.DARKROOM_OVERLAY.apply(overlay[0] || overlay);

    const panel = razyui.el('div', { className: CLS.DARKROOM_PANEL });
    PART.DARKROOM_PANEL.apply(panel[0] || panel);

    // Header
    const header = razyui.el('div', { className: CLS.DARKROOM_HEADER });
    PART.DARKROOM_HEADER.apply(header[0] || header);

    const title = razyui.el('span', {
        className: CLS.DARKROOM_TITLE,
        textContent: config.placeholder || 'Edit Tags'
    });
    PART.DARKROOM_TITLE.apply(title[0] || title);
    header.append(title);

    const closeBtn = razyui.el('button', {
        type: 'button',
        className: CLS.DARKROOM_CLOSE,
        innerHTML: SVG.DARKROOM_CLOSE
    });
    PART.DARKROOM_CLOSE.apply(closeBtn[0] || closeBtn);
    header.append(closeBtn);

    panel.append(header);

    // Body
    const body = razyui.el('div', { className: CLS.DARKROOM_BODY });
    PART.DARKROOM_BODY.apply(body[0] || body);
    panel.append(body);

    overlay.append(panel);
    razyui(document.body).append(overlay[0]);

    // Use shared popup stack so darkroom always appears above existing overlays (e.g. Dialog)
    zIndexRegistry.acquire(overlay[0]);

    // Move container into darkroom body, switch to full editing mode
    const $container = razyui(container);
    $container.removeClass(STATE_CLS.COMPACT).removeClass(STATE_CLS.SINGLE_LINE);
    if (overflowBadge) overflowBadge.css('display', 'none');
    $container.find(SEL.OVERFLOW_HIDDEN).each(c => razyui(c).removeClass(STATE_CLS.OVERFLOW_HIDDEN));
    body.append(container);

    // Focus input after transition
    requestAnimationFrame(() => textInput.focus());

    return { overlay, ghost, closeBtn };
}

/**
 * Close the darkroom and return container to its original position.
 *
 * @param {object} ctx — { container, config, ghost, compactAnchor, overlay, overflowBadge }
 */
export function closeDarkroom(ctx) {
    const { container, config, ghost, compactAnchor, overlay } = ctx;

    // Replace ghost with the real container
    if (ghost?.parent()[0]) {
        ghost.before(container);
        ghost[0].remove();
    } else {
        // Fallback to anchor
        compactAnchor.before(container);
    }

    const $container = razyui(container);
    $container.addClass(STATE_CLS.COMPACT);
    if (config.singleLine) {
        $container.addClass(STATE_CLS.SINGLE_LINE);
    }

    // Tear down overlay
    zIndexRegistry.release(overlay[0]);
    overlay[0].remove();
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Destroy all DOM elements created by ClipBox and restore the native input.
 *
 * @param {object} ctx — { floating, container, ghost, compactAnchor, inputEl }
 */
export function destroyDOM(ctx) {
    const { floating, container, ghost, compactAnchor, inputEl } = ctx;
    if (floating?.parentNode) floating.remove();
    if (container?.parentNode) container.remove();
    if (ghost?.parent()[0]) ghost[0].remove();
    if (compactAnchor?.parent()[0]) compactAnchor[0].remove();
    if (inputEl) razyui(inputEl).css('display', '');
}
