/**
 * @fileoverview ClipBox helpers — pure utility functions.
 * @module module/ClipBox/helpers
 */

/**
 * Parse a raw separator-delimited string into an array of unique chip objects.
 *
 * @param {string} raw — the raw input value (e.g. "a, b, c")
 * @param {string} separator — delimiter character
 * @param {boolean} allowDuplicate — whether duplicates are permitted
 * @returns {{ id: string, value: string, label: string }[]}
 */
export function parseInitialParts(raw, separator, allowDuplicate) {
    if (!raw.trim()) return [];

    const parts = raw.split(separator).map(s => s.trim()).filter(Boolean);
    const chips = [];
    for (const part of parts) {
        if (!allowDuplicate && chips.some(c => c.id === part)) continue;
        chips.push({ id: part, value: part, label: part });
    }
    return chips;
}

/**
 * Default id extractor for remote suggestion items.
 *
 * @param {object} item — remote data item
 * @returns {string}
 */
export function defaultMapId(item) {
    return String(item.id ?? item.value ?? '');
}

/**
 * Default value extractor for remote suggestion items.
 *
 * @param {object} item — remote data item
 * @returns {string}
 */
export function defaultMapValue(item) {
    return String(item.value ?? item.id ?? '');
}

/**
 * Default label extractor for remote suggestion items.
 *
 * @param {object} item — remote data item
 * @returns {string}
 */
export function defaultMapLabel(item) {
    return String(item.label ?? item.text ?? item.name ?? '');
}

/**
 * Normalise an array of mixed string / object items into chip objects.
 *
 * @param {(string | { id?: string, value: string, label?: string, text?: string })[]} items
 * @returns {{ id: string, value: string, label: string }[]}
 */
export function normalizeChipItems(items) {
    return items.map(item => {
        if (typeof item === 'string') return { id: item, value: item, label: item };
        const value = String(item.value ?? '');
        return {
            id: String(item.id ?? value),
            value,
            label: String(item.label ?? item.text ?? value ?? ''),
        };
    });
}
